#define SPI_H

#include <stdint.h>
#include <stdbool.h>

typedef struct {
    uint32_t clock_hz;
    uint8_t  mode;
    uint8_t  bits_per_word;
    bool     lsb_first;
    uint8_t  cs_polarity;  /* NEW: chip-select polarity, 0=active-low */
} spi_config_t;

int spi_open(uint8_t bus, const spi_config_t *cfg);
int spi_transfer(uint8_t bus, const uint8_t *tx, uint8_t *rx, uint16_t len);
void spi_close(uint8_t bus);

#endif /* SPI_H */

